frappe.query_reports["Sales Person Target Variance by Item"] = {
    filters: [
        {
            fieldname: "fiscal_year",
            label: "Fiscal Year",
            fieldtype: "Link",
            options: "Fiscal Year",
            reqd: 1
        },
        {
            fieldname: "from_date",
            label: "From Date",
            fieldtype: "Date",
            reqd: 1
        },
        {
            fieldname: "to_date",
            label: "To Date",
            fieldtype: "Date",
            reqd: 1
        },
        {
            fieldname: "parent_sales_person",
            label: "Parent Sales Person",
            fieldtype: "Link",
            options: "Sales Person",
            get_query: () => {
                return {
                    filters: {
                        is_group: 1  // only parent sales persons
                    }
                };
            }
        },
        {
            fieldname: "sales_person",
            label: "Sales Person",
            fieldtype: "Link",
            options: "Sales Person",
            get_query: () => {
                return {
                    filters: {
                        is_group: 0  // only non-parent sales persons
                    }
                };
            }
        }
    ],
    // 🚫 prevents auto-loading
    onload: function(report) {
        report.page.set_primary_action(__('Refresh'), function() {
            report.refresh();
        });
        report.page.set_primary_action(__('Refresh'), () => report.refresh());
        report.page.set_primary_action(__('Run Report'), () => report.refresh());
        report.page.set_title(__("Sales Person Target Variance by Item"));
    }

