DECLARE done INT DEFAULT FALSE;
    DECLARE v_docname VARCHAR(255);
    DECLARE v_doctype VARCHAR(50);
    DECLARE v_item_code VARCHAR(255);
    DECLARE v_qty INT;
    DECLARE v_series_start INT;
    DECLARE n INT DEFAULT 0;

    -- cursor and handler
    DECLARE cur CURSOR FOR
        SELECT
            sri.parent AS In_document,
            'Stock Requisition' AS In_Doctype,
            sri.item_code,
            sri.qty,
            sri.custom_series_booklet_from
        FROM `tabStock Reconciliation Item` sri
        JOIN `tabItem` i ON i.item_code = sri.item_code
        WHERE i.item_group = 'OS BB BOOKLET'
          AND sri.warehouse = 'Office Supplies - QC'
        UNION ALL
        SELECT
            pri.parent AS docname,
            'Purchase Receipt' AS doctype,
            pri.item_code,
            pri.qty,
            pri.custom_series_booklet_from
        FROM `tabPurchase Receipt Item` pri
        JOIN `tabItem` i ON i.item_code = pri.item_code
        WHERE i.item_group = 'OS BB BOOKLET'
          AND pri.warehouse = 'Office Supplies - QC';

    DECLARE CONTINUE HANDLER FOR NOT FOUND SET done = TRUE;

    -- temporary table
    DROP TEMPORARY TABLE IF EXISTS tmp_booklet_series;
    CREATE TEMPORARY TABLE tmp_booklet_series (
        In_document VARCHAR(255),
        In_doctype VARCHAR(50),
        item_code VARCHAR(255),
        series_from INT,
        series_to INT
    );

    -- open cursor
    OPEN cur;

    read_loop: LOOP
        FETCH cur INTO v_docname, v_doctype, v_item_code, v_qty, v_series_start;
        IF done THEN
            LEAVE read_loop;
        END IF;

        SET n = 0;
        WHILE n < v_qty DO
            INSERT INTO tmp_booklet_series (In_document, In_doctype, item_code, series_from, series_to)
            VALUES (
                v_docname,
                v_doctype,
                v_item_code,
                v_series_start + (n * 50),
                v_series_start + (n * 50) + 49
            );
            SET n = n + 1;
        END WHILE;

    END LOOP;

    CLOSE cur;

    -- return result
	DROP TEMPORARY TABLE IF EXISTS TEMP_STOCK_ENTRY;
	CREATE TEMPORARY TABLE TEMP_STOCK_ENTRY (
		series_from INT,
		item_code VARCHAR(255),
		Out_document VARCHAR(255),
		Out_doctype VARCHAR(50),
		Out_Date DATETIME,
		Warehouse VARCHAR(255)
	    );
	    
	INSERT INTO TEMP_STOCK_ENTRY (series_from, item_code, Out_document, Out_doctype, Out_Date, Warehouse)
	SELECT IFNULL(a.custom_series_booklet_from,0), a.item_code,b.name, b.stock_entry_type, b.Posting_date, b.from_warehouse
	FROM `tabStock Entry Detail` a, `tabStock Entry` b
	WHERE a.parent = b.name
	AND a.item_group = 'OS BB BOOKLET'
	AND  b.stock_entry_type IN ('Material Issue','Material Transfer')
	AND a.custom_series_booklet_from IS NOT NULL;
    
    
    SELECT DISTINCT
    a.*, 
    b.Out_document, 
    b.Out_doctype, 
    b.Out_Date, 
    b.Warehouse
	FROM tmp_booklet_series a
	LEFT JOIN TEMP_STOCK_ENTRY b 
	    ON a.item_code = b.item_code
	   AND a.series_from = b.series_from
	ORDER BY a.item_code, a.series_from ASC;
